async function testSailingJsEndpoint() {
  const BASE = 'http://localhost:3001';
  const res = await fetch(BASE + '/api/sailing-js');
  assertEquals(res.status, 200, 'Should return 200');

  const contentType = res.headers.get('content-type') || '';
  assert(contentType.includes('javascript'), 'Should have JavaScript content type');

  const js = await res.text();
  assert(js.length > 30000, 'JS should be substantial (>30KB)');

  // Verify water detection functions are present
  assert(js.includes('function latLonToTilePixel'), 'Should have latLonToTilePixel');
  assert(js.includes('function tilePixelToLatLon'), 'Should have tilePixelToLatLon');
  assert(js.includes('function isWaterPixel'), 'Should have isWaterPixel');
  assert(js.includes('function loadTileToCanvas'), 'Should have loadTileToCanvas');
  assert(js.includes('function findNearestWater'), 'Should have findNearestWater');
  assert(js.includes('function validateAndSetBoatPosition'), 'Should have validateAndSetBoatPosition');

  // Verify event handlers use the validator
  assert(js.includes("validateAndSetBoatPosition(pos.lat, pos.lng, 'drag')"), 'Dragend should use validator');
  assert(js.includes("validateAndSetBoatPosition(e.latlng.lat, e.latlng.lng, 'click')"), 'Click should use validator');
  assert(js.includes("validateAndSetBoatPosition(pos.coords.latitude, pos.coords.longitude, 'geolocation')"), 'Geolocation should use validator');

  // Verify weather area overlay functions
  assert(js.includes('function initRainViewer'), 'Should have initRainViewer');
  assert(js.includes('function fetchGridOverlays'), 'Should have fetchGridOverlays');
  assert(js.includes('function renderCloudAreas'), 'Should have renderCloudAreas');
  assert(js.includes('function renderPressureAreas'), 'Should have renderPressureAreas');
  assert(js.includes('function updateGridOverlays'), 'Should have updateGridOverlays');

  // Verify overlay state variables
  assert(js.includes('var rainRadarLayer'), 'Should have rainRadarLayer state');
  assert(js.includes('var cloudOverlayLayer'), 'Should have cloudOverlayLayer state');
  assert(js.includes('var pressureOverlayLayer'), 'Should have pressureOverlayLayer state');

  // Verify new layer keys
  assert(js.includes('radar: true'), 'Should have radar layer key');
  assert(js.includes('cloudMap: true'), 'Should have cloudMap layer key');
  assert(js.includes('pressureMap: true'), 'Should have pressureMap layer key');

  // Verify the draggable-controls module is present
  assert(js.includes('function setupDraggablePanels'), 'Should have setupDraggablePanels');
  assert(js.includes('function makeDraggable'), 'Should have makeDraggable');
  assert(js.includes('function pinElement'), 'Should have pinElement');
  assert(js.includes('function clampToViewport'), 'Should have clampToViewport');
  assert(js.includes('function loadSavedPositions'), 'Should have loadSavedPositions');
  assert(js.includes('var DRAGGABLE_IDS'), 'Should declare the draggable id list');

  // Verify each floating control id is registered as draggable (route-panel now included)
  ['conditions-panel', 'compass-panel', 'layer-panel', 'timeline-panel', 'info-bar', 'action-buttons', 'route-panel'].forEach(function(id) {
    assert(js.includes("'" + id + "'"), 'DRAGGABLE_IDS should include ' + id);
  });

  // Verify boot wires the draggable panels up after setupEvents
  assert(js.includes('setupDraggablePanels();'), 'Boot should call setupDraggablePanels');

  // Verify the route planning module is present
  assert(js.includes('function addRouteWaypoint'), 'Should have addRouteWaypoint');
  assert(js.includes('function undoRouteWaypoint'), 'Should have undoRouteWaypoint');
  assert(js.includes('function clearRoute'), 'Should have clearRoute');
  assert(js.includes('function toggleRouteMode'), 'Should have toggleRouteMode');
  assert(js.includes('function renderRoute'), 'Should have renderRoute');
  assert(js.includes('function recomputeRoute'), 'Should have recomputeRoute');
  assert(js.includes('function renderRoutePanel'), 'Should have renderRoutePanel');
  assert(js.includes('function setupRouteControls'), 'Should have setupRouteControls');
  assert(js.includes('var routeMode'), 'Should declare routeMode state');
  assert(js.includes('var routeWaypoints'), 'Should declare routeWaypoints state');

  // Verify boot wires the route controls up and the click branch exists
  assert(js.includes('setupRouteControls();'), 'Boot should call setupRouteControls');
  assert(js.includes('addRouteWaypoint(e.latlng.lat, e.latlng.lng)'), 'Map click should add a waypoint in route mode');
  assert(js.includes("fetch('/api/route-plan'"), 'Should POST to /api/route-plan');
}
